        updatedAt
        headRefName
        baseRefName
        isCrossRepository
        mergeable
        mergeStateStatus
        reviewDecision
        statusCheckRollup {
          state
          contexts(last: 1) {
            totalCount
            checkRunCountsByState { state count }
            statusContextCountsByState { state count }
          }
        }
        reviewThreads(first: 100) {
          totalCount
          nodes { isResolved }
        }
      }
    }
